var prims = ['string','number','boolean','Date','UUID','decimal','date','uuid'];
var attrs = attributes || [];
var nonPrim = attrs.filter(function (a) { return !a.reference; }).map(function (a) { return a.type; }).filter(function (t) { return prims.indexOf(t) === -1 && t !== name; });
return Array.from(new Set(nonPrim));

var primZod = { string: 'z.string()', number: 'z.number()', boolean: 'z.boolean()', decimal: 'z.number()', date: 'z.string().datetime()', uuid: 'z.string().uuid()' };
var primTs = { string: 'string', number: 'number', boolean: 'boolean', decimal: 'number', date: 'string', uuid: 'string' };
function zodFor(a) {
  var isPrim = a.type in primZod;
  var base;
  if (a.reference && !isPrim) { base = 'z.string().uuid()'; }
  else if (isPrim) {
    base = primZod[a.type];
    if (a.primaryKey && a.type === 'uuid') { base += '.default(() => crypto.randomUUID())'; }
    else if (a.defaultValue !== undefined && a.defaultValue !== '') {
      var v = a.type === 'string' ? ("'" + a.defaultValue + "'") : a.defaultValue;
      base += '.default(' + v + ')';
    } else if (a.type === 'boolean') { base += '.default(false)'; }
    if (a.required && a.type === 'string' && !a.defaultValue) { base = 'z.string().min(1)'; }
  } else { base = pascalCase(a.type) + 'Schema'; }
  if (a.multiValue) { base = 'z.array(' + base + ').default([])'; }
  else if (!a.required && !a.primaryKey) { base += '.optional()'; }
  return base;
}
function tsFor(a) {
  var isPrim = a.type in primTs;
  var base = (a.reference && !isPrim) ? 'string' : (primTs[a.type] || pascalCase(a.type || ''));
  if (a.multiValue) { base += '[]'; }
  return base;
}
return (attributes || []).map(function (a) {
  return { name: a.name, camel: camelCase(a.name), required: a.required, tsType: tsFor(a), zodType: zodFor(a) };
});

