{{/each}}

{{#if selfRef}}
{{#each nonPrimitives}}
import type { {{pascalCase this}} } from './{{pascalCase this}}'
{{/each}}
export type {{pascalCase name}} = {
{{#each attrSpecs}}
  {{camel}}{{#unless required}}?{{/unless}}: {{{tsType}}}
{{/each}}
}

export const {{pascalCase name}}Schema: z.ZodType<{{pascalCase name}}> = z.lazy(() =>
z.object({
{{#each attrSpecs}}
  {{camel}}: {{{zodType}}},
{{/each}}
})
)
{{/if}}

{{#unless selfRef}}
export const {{pascalCase name}}Schema = z.object({
{{#each attrSpecs}}
  {{camel}}: {{{zodType}}},
{{/each}}
})

export type {{pascalCase name}} = z.infer<typeof {{pascalCase name}}Schema>
{{/unless}}
